import{_ as a,o,c as t,a2 as n}from"./chunks/framework.DZO5kRrk.js";const h=JSON.parse('{"title":"Agent 工具调用核心原理与 MCP 接入实战总结","description":"","frontmatter":{},"headers":[],"relativePath":"docs/ai/09-agent-mcp-learning.md","filePath":"docs/ai/09-agent-mcp-learning.md"}'),s={name:"docs/ai/09-agent-mcp-learning.md"};function l(i,e,c,r,d,g){return o(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="agent-工具调用核心原理与-mcp-接入实战总结" tabindex="-1">Agent 工具调用核心原理与 MCP 接入实战总结 <a class="header-anchor" href="#agent-工具调用核心原理与-mcp-接入实战总结" aria-label="Permalink to &quot;Agent 工具调用核心原理与 MCP 接入实战总结&quot;">​</a></h1><p><img src="https://api.cheatppf.xyz/i/mr8ts338-wna0lm.png" alt="首图"></p><p>本文档总结了如何基于 LangChain 框架构建带有外部工具调用能力的 AI Agent，并重点探讨了如何接入 MCP (Model Context Protocol) 服务以及使用 LCEL (LangChain Expression Language) 编排复杂的执行流。通过 Agent 与工具的结合，我们可以突破大模型本身的信息孤岛，让其具备与真实世界交互（如查询地图、执行代码）的能力。</p><hr><h2 id="一、核心架构-agent-的执行逻辑与-lcel-编排" tabindex="-1">一、核心架构：Agent 的执行逻辑与 LCEL 编排 <a class="header-anchor" href="#一、核心架构-agent-的执行逻辑与-lcel-编排" aria-label="Permalink to &quot;一、核心架构：Agent 的执行逻辑与 LCEL 编排&quot;">​</a></h2><p>与传统的单向对话或纯 RAG 检索不同，Agent 拥有“自主决策”的能力。它的标准工作流通常包含一个基于状态的循环：</p><ul><li><strong>大模型思考 (Thinking)</strong>：将用户问题和上下文交由大模型，大模型决定是直接给最终回答，还是需要调用特定的外部工具。</li><li><strong>工具路由 (Routing)</strong>：代码需要捕获模型给出的 <code>tool_calls</code> 信号，进入工具执行的分支逻辑。</li><li><strong>工具执行 (Execution)</strong>：调用本地或远程的工具接口（如 MCP 服务），获取真实的业务数据。</li><li><strong>结果观察 (Observation)</strong>：将工具返回的数据包装回传给大模型，供其进行二次思考和总结。</li></ul><p>在实战中，我们使用 <strong>LCEL (LangChain Expression Language)</strong> 来声明式地编排上述复杂的循环与条件分支逻辑。</p><hr><h2 id="二、关键组件选型与实战解析" tabindex="-1">二、关键组件选型与实战解析 <a class="header-anchor" href="#二、关键组件选型与实战解析" aria-label="Permalink to &quot;二、关键组件选型与实战解析&quot;">​</a></h2><h3 id="_1-接入-mcp-服务获取标准工具" tabindex="-1">1. 接入 MCP 服务获取标准工具 <a class="header-anchor" href="#_1-接入-mcp-服务获取标准工具" aria-label="Permalink to &quot;1. 接入 MCP 服务获取标准工具&quot;">​</a></h3><p>MCP (Model Context Protocol) 提供了一种标准化的方式来让大模型连接各种外部数据和服务。在本项目中，我们实战了通过 MCP 接入高德地图的能力。</p><ul><li><strong>MultiServerMCPClient</strong>：我们利用 <code>@langchain/mcp-adapters</code> 初始化客户端，通过 HTTP 连接到了高德的 MCP 节点。这样，无需我们手写繁琐的 API 请求封装代码，大模型就能直接“发现”并使用高德提供的地理编码或周边搜索等专业地图工具。</li><li><strong>工具与模型绑定</strong>：通过 <code>mcpClient.getTools()</code> 异步获取可用工具列表后，使用 <code>model.bindTools(tools)</code> 这一关键步骤，将外部能力（Schema）注入到大模型的知识体系中。</li></ul><h3 id="_2-构建核心工具执行器-tool-executor" tabindex="-1">2. 构建核心工具执行器 (Tool Executor) <a class="header-anchor" href="#_2-构建核心工具执行器-tool-executor" aria-label="Permalink to &quot;2. 构建核心工具执行器 (Tool Executor)&quot;">​</a></h3><p>当大模型决定调用工具时，它只会返回工具的名称和参数。我们需要一个执行器来真正跑通这个调用链路。</p><ul><li><strong>查找与匹配</strong>：在自定义的 <code>RunnableLambda</code> 中，我们遍历大模型返回的 <code>tool_calls</code> 数组，在预初始化的 <code>tools</code> 列表中寻找对应的具体工具实例 (<code>t.name === toolCall.name</code>)。</li><li><strong>执行与包装</strong>：执行 <code>findTool.invoke(toolCall.args)</code> 获取真实结果后，<strong>必须</strong>将其格式化为标准的规范。在 LangChain 体系下，我们将执行结果包装为 <code>ToolMessage</code> 传回上下文。如果不这么做，大模型在后续判断时将会报错或迷失上下文。</li></ul><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 规范的 ToolMessage 包装示例</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">toolResults.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">push</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ToolMessage</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  content: contenStr, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 工具返回的字符串化数据</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  tool_call_id: toolCall.id </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 必须与大模型的调用 ID 一一对应</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}))</span></span></code></pre></div><h3 id="_3-lcel-分支路由-runnablebranch-与状态管理" tabindex="-1">3. LCEL 分支路由：RunnableBranch 与状态管理 <a class="header-anchor" href="#_3-lcel-分支路由-runnablebranch-与状态管理" aria-label="Permalink to &quot;3. LCEL 分支路由：RunnableBranch 与状态管理&quot;">​</a></h3><p>在纯 LCEL 架构下处理 Agent 循环，最核心的难点在于<strong>条件分支的解耦</strong>。</p><p><img src="https://api.cheatppf.xyz/i/mr8tsa72-iinc89.png" alt="流程图"></p><ul><li><strong>条件分支判定</strong>：我们使用了 LCEL 的 <code>RunnableBranch</code>。它的逻辑声明非常清晰：通过一个判断函数检查大模型返回的数据中是否包含工具调用请求 (<code>!state.response.tool_calls || state.response.tool_calls.length === 0</code>)。</li><li><strong>结束分支</strong>：如果判断为真（即无需调用工具），说明大模型已经推导出了最终答案。此时只需将结果存入 <code>messages</code>，并标记核心状态 <code>done: true</code> 以通知外层系统中断执行。</li><li><strong>继续分支（默认）</strong>：如果判断为假（即需要调用工具），则通过组合 <code>RunnableSequence</code> 依次执行：将模型的工具调用指令压入历史 -&gt; 触发 <code>toolExecutor</code> 获取外部数据 -&gt; 将工具结果一并压入历史 -&gt; 标记 <code>done: false</code> 以便外层循环继续运转。</li></ul><h3 id="_4-复杂业务流编排对比-rag-与-agent" tabindex="-1">4. 复杂业务流编排对比：RAG 与 Agent <a class="header-anchor" href="#_4-复杂业务流编排对比-rag-与-agent" aria-label="Permalink to &quot;4. 复杂业务流编排对比：RAG 与 Agent&quot;">​</a></h3><p>通过对比我们实现的《长安的荔枝》小说 RAG 检索（<code>book.ts</code>）和地图工具 Agent（<code>map.ts</code>），可以清晰看到 LCEL 在不同场景下表现出的不同流派：</p><ul><li><strong>线性流水线 (RAG 单次通过)</strong>：在小说检索实战中，我们只需使用 <code>RunnableSequence</code> 串联起 <code>milvusSearch</code> -&gt; <code>buildPrompt</code> -&gt; <code>model</code> -&gt; <code>StringOutputParser</code>。这是一条单向通行的高速公路，一环扣一环，只需 <code>invoke</code> 或 <code>stream</code> 一次即可闭环。</li><li><strong>状态机循环 (Agent 多次迭代)</strong>：在处理工具调用时，流程变得不再线性。我们需要在代码的最外层维护一个包含 <code>messages</code> 和 <code>done</code> 的全局 <code>state</code>。通过外层 <code>for</code> 循环（设定最大迭代次数如 <code>maxInterations = 30</code>）来不断驱动内部的 LCEL 路由网络，直到状态转变为结束。这不仅解决了多轮推导的问题，也有效防止了模型因无法理解工具而陷入无限死循环的风险。</li></ul>`,24)])])}const u=a(s,[["render",l]]);export{h as __pageData,u as default};
